        if(i + p[i] < a[i]) {
            cti = i;
            break;
        }
    }

    int cnt = 0;
    int64_t s_i = p[cti] + cti;

    for (int j = cti + 1; j < n; ++j) {
        if (a[j] <= cnt) ++cnt;
        else s_i += a[j] - cnt;
    }

    if (s_i < a[cti]) cout << "No\n";
    else cout << "Yes\n";
}

int main() {
    ios::sync_with_stdio(false); cin.tie(nullptr);

    int t; cin >> t;

    while(t--) solve();
    return 0;
}

```
 Code O(n*logn) - IceKnight1093
```
#include "bits/stdc++.h"
using namespace std;
using ll = long long int;
mt19937_64 RNG(chrono::high_resolution_clock::now().time_since_epoch().count());

#include <ext/pb_ds/assoc_container.hpp>
#include <ext/pb_ds/tree_policy.hpp>
using namespace __gnu_pbds;
template<class T>
using Tree = tree<T, null_type, less<T>, rb_tree_tag, tree_order_statistics_node_update>;

struct FT {
    vector<ll> s;
    FT(int n) : s(n) {}
    void update(int pos, ll dif) { // a[pos] += dif↵
        for (; pos < size(s); pos |= pos + 1) s[pos] += dif;
    }
    ll query(int pos) { // sum of values in [0, pos)
        ll res = 0;
        for (; pos > 0; pos &= pos - 1) res += s[pos-1];
        return res;
    }
};

int main()
{
    ios::sync_with_stdio(false); cin.tie(0);

    map<vector<int>, bool> cache;
    auto brute = [&] (const auto &self, auto v) -> bool {
        if (ranges::max(v) == 0) return true;
        if (cache.find(v) != cache.end()) return cache[v];

        for (int i = 1; i < v.size(); ++i) {
            if (v[i] > 0) {
                auto w = v;
                --w[i];
                swap(w[i], w[i-1]);
                bool res = self(self, w);

                if (res) return cache[v] = true;
            }
        }
        return cache[v] = false;
    };

    auto solve = [&] (auto v) {
        int n = size(v);

        vector<int> b(n);
        Tree<array<int, 2>> cur;
        for (int i = 0; i < n; ++i) {
            if (v[i] == 0) b[i] = i;
            else {
                // v[i]-th largest element↵
                if (cur.size() >= v[i]) {
                    int want = cur.size() - v[i];
                    auto [val, _] = *cur.find_by_order(want);
                    b[i] = val;
                }
                else b[i] = -1;
            }
            cur.insert({b[i], i});
        }

        vector deactivate(n+1, vector<int>());
        for (int i = 0; i < n; ++i)
            if (b[i] >= 0) deactivate[b[i]].push_back(i);

        ll pref = 0;
        for (int i = 0; i < n; ++i) pref += v[i] + 1;

        FT fen(n);
        ll suf = 0;
        for (int i = n-1; i >= 0; --i) {
            pref -= v[i] + 1;

            ranges::reverse(deactivate[i]);
            for (int x : deactivate[i]) {
                if (v[x]) {
                    int sub = fen.query(x+1) - fen.query(i+1);
                    sub = x - i - sub;
                    suf -= v[x] - sub;
                    fen.update(x, -1);
                }
                suf -= fen.query(n) - fen.query(x);
            }
            ll have = pref + suf;
            if (v[i] > have) return false;
            if (v[i] > 0) {
                suf += v[i];
                fen.update(i, 1);
            }
        }
        return true;
    };

    int t; cin >> t;
    while (t--) {
        int n; cin >> n;
        vector a(n, 0);
        for (int &x : a) cin >> x;

        if (solve(a)) cout << "Yes\n";
        else cout << "No\n";
    }
}

